#include<cstdio>
#include<bitset>
#include<algorithm>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=1e5+10,W=1e5;std::bitset<N> S,I,ans;
int cnt[N],L,R,n,a[N],Q;struct Nd{int l,r,idx,opt,x;}q[N];
inline void ins(int x){if(!(cnt[x]++))S[x]=true,I[W-x]=true;}
inline void del(int x){if(!(--cnt[x]))S[x]=false,I[W-x]=false;}
int main()
{
	n=read();Q=read();rep(1,n,i)a[i]=read();rep(1,Q,i)q[i].opt=read(),q[i].l=read(),q[i].r=read(),q[i].x=read(),q[i].idx=i;
	std::sort(q+1,q+Q+1,[&](const Nd&x,const Nd&y){return (x.l>>8)==(y.l>>8)?((x.l>>8)&1?x.r>y.r:x.r<y.r):x.l<y.l;});
	L=q[1].l;R=L-1;rep(1,Q,i)
	{
		while(R<q[i].r)ins(a[++R]);while(L>q[i].l)ins(a[--L]);while(R>q[i].r)del(a[R--]);while(L<q[i].l)del(a[L++]);
		if(q[i].opt==1)ans[q[i].idx]=(S&(S<<q[i].x)).count();else if(q[i].opt==2)ans[q[i].idx]=(S&(I>>(W-q[i].x))).count();
		else for(int j=1;j*j<=q[i].x;++j)if(q[i].x%j==0&&S[j]&&S[q[i].x/j]){ans[q[i].idx]=true;break;}
	}
	rep(1,Q,i)puts(ans[i]?"hana":"bi");return 0;
}
